/**
 * PWA assets served as inline content via app.ts routes.
 *
 * These files cannot live in src/web/public/ because the Agentuity CLI generates
 * unquoted TypeScript property names for files with dots (e.g. manifest.json, sw.js)
 * in src/generated/routes.ts, breaking the deployment typecheck. Additionally,
 * production serveStatic does not strip the /public/ prefix, so icon requests
 * for /public/icons/* fail with 404. Instead, all PWA assets are served as
 * explicit routes registered in app.ts (no auth middleware).
 */

